import { createHash, randomBytes } from 'crypto'

// Simple secure password hashing using PBKDF2 (no external deps needed)
const ITERATIONS = 10000
const KEY_LENGTH = 64
const DIGEST = 'sha512'

export function hashPassword(password: string): string {
  const salt = randomBytes(16).toString('hex')
  const hash = createHash('sha512')
    .update(salt + password)
    .digest('hex')
  // Multi-round hashing for added security
  let final = hash
  for (let i = 0; i < ITERATIONS; i++) {
    final = createHash(DIGEST).update(salt + final).digest('hex')
  }
  return `${salt}:${final}`
}

export function verifyPassword(password: string, stored: string): boolean {
  const [salt, hash] = stored.split(':')
  if (!salt || !hash) return false
  let final = createHash('sha512')
    .update(salt + password)
    .digest('hex')
  for (let i = 0; i < ITERATIONS; i++) {
    final = createHash(DIGEST).update(salt + final).digest('hex')
  }
  return final === hash
}

// Session token generation
export function generateToken(): string {
  return randomBytes(32).toString('hex')
}

// Session store: in-memory map persisted on globalThis to survive hot reloads in dev
// In production, replace with Redis or DB-backed session table
type Session = {
  userId: string
  token: string
  expiresAt: number
}

const globalForSessions = globalThis as unknown as {
  __sessions: Map<string, Session> | undefined
}

const sessions = globalForSessions.__sessions ?? new Map<string, Session>()

if (!globalForSessions.__sessions) {
  globalForSessions.__sessions = sessions
}

if (process.env.NODE_ENV !== 'production') {
  globalForSessions.__sessions = sessions
}

const SESSION_TTL_MS = 1000 * 60 * 60 * 24 * 7 // 7 days

export function createSession(userId: string): string {
  const token = generateToken()
  sessions.set(token, {
    userId,
    token,
    expiresAt: Date.now() + SESSION_TTL_MS,
  })
  return token
}

export function getSession(token: string): Session | null {
  const session = sessions.get(token)
  if (!session) return null
  if (session.expiresAt < Date.now()) {
    sessions.delete(token)
    return null
  }
  return session
}

export function destroySession(token: string): void {
  sessions.delete(token)
}

export function clearAllSessionsForUser(userId: string): void {
  for (const [token, session] of sessions.entries()) {
    if (session.userId === userId) {
      sessions.delete(token)
    }
  }
}

// Alias for clarity at call sites
export const destroyAllUserSessions = clearAllSessionsForUser
